SELECT 
FROM t_owner_dispute
WHERE tenant_id = #{tenantId}
  AND raised_by_owner_id = #{ownerId}
ORDER BY raised_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT 
FROM t_owner_dispute
WHERE tenant_id = #{tenantId}

    AND current_review_level = #{level}


    AND status = #{status}

ORDER BY raised_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT d.dispute_id, d.tenant_id, d.raised_by_owner_id, d.related_property_opid, d.dispute_kind, d.related_entity_type, d.related_entity_id, d.current_review_level, d.status, d.business_payload::text AS business_payload, d.raised_at, d.escalated_at, d.closed_at, d.litigation_outcome, d.litigation_judgement_url, d.version, d.create_time, d.update_time FROM t_owner_dispute d JOIN c_owner_property op ON op.opid = d.related_property_opid AND op.tenant_id = d.tenant_id WHERE
(op.tenant_id = #{bs.tenantId} AND op.building_id = #{bs.buildingId})
1 = 0
AND d.current_review_level = #{level}
AND d.status = #{status}
ORDER BY d.raised_at DESC LIMIT #{limit} OFFSET #{offset}
